function MarkdownEditorWidget() {
  const [text, setText] = React.useState('# Hello\n\nType **markdown** here.');

  function mdToHtml(md) {
    return md
      .replace(/^### (.*$)/gim, '<h3>$1</h3>')
      .replace(/^## (.*$)/gim, '<h2>$1</h2>')
      .replace(/^# (.*$)/gim, '<h1>$1</h1>')
      .replace(/\*\*(.*?)\*\*/gim, '<b>$1</b>')
      .replace(/\*(.*?)\*/gim, '<i>$1</i>')
      .replace(/`([^`]+)`/gim, '<code style="background:#1e293b;padding:2px 4px;border-radius:4px;">$1</code>')
      .replace(/\n/gim, '<br />');
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column' }}>
      <h3 style={{ margin: 0, marginBottom: 10 }}>Markdown Editor</h3>
      <div style={{ display: 'flex', gap: 10, flex: 1, minHeight: 0 }}>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          style={{
            flex: 1,
            background: '#1e293b',
            color: '#e2e8f0',
            border: '1px solid #334155',
            borderRadius: 8,
            padding: 10,
            fontFamily: 'system-ui, sans-serif',
            fontSize: 13,
            resize: 'none'
          }}
        />
        <div
          style={{
            flex: 1,
            background: '#1e293b',
            border: '1px solid #334155',
            borderRadius: 8,
            padding: 10,
            fontSize: 13,
            overflow: 'auto'
          }}
          dangerouslySetInnerHTML={{ __html: mdToHtml(text) }}
        />
      </div>
    </div>
  );
}
render(<MarkdownEditorWidget/>);
